+function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  characterType: CharacterType,
+  x: number,
+  y: number,
+  scale: number,
+  frame: number,
+) {
+  const frames = IDLE_FRAMES_MAP[characterType] || [SPRITE_MAP[characterType]];
+  const frameIndex = frame % frames.length;
+  const sprite = frames[frameIndex];
+  const palette = PALETTE_MAP[characterType];
+
+  // Calculate breathing vertical offset: subtle sine wave based on frame
+  // breathing offset cycles every 4 frames: 0, +1, 0, -1 pixels
+  const breathingOffsets = [0, 1, 0, -1];
+  const yOffset = breathingOffsets[frameIndex] || 0;
+
+  // Draw elliptical drop shadow beneath character
+  // Shadow parameters
+  const shadowWidth = sprite[0].length * scale;
+  const shadowHeight = 3;
+  const shadowX = x;
+  const shadowY = y + (sprite.length * scale) - shadowHeight / 2 + yOffset;
+
+  ctx.save();
+  ctx.fillStyle = 'rgba(26, 26, 46, 0.3)'; // #1a1a2e with 0.3 alpha
+  ctx.beginPath();
+  ctx.ellipse(
+    shadowX + shadowWidth / 2,
+    shadowY,
+    shadowWidth / 2,
+    shadowHeight,
+    0,
+    0,
+    2 * Math.PI,
+  );
+  ctx.fill();
+  ctx.restore();
+
+  // Draw 1px dark outline by drawing silhouette behind character
+  // Outline color
+  const outlineColor = '#1a1a2e';
+
+  // Draw silhouette with outline color offset by -1,0,1 px in x and y directions
+  // To simulate 1px outline, draw silhouette 4 times around original position
+  const outlineOffsets = [
+    [-1, 0],
+    [1, 0],
+    [0, -1],
+    [0, 1],
+  ];
+
+  for (const [ox, oy] of outlineOffsets) {
+    drawSpriteDef(ctx, sprite, Object.fromEntries(Object.keys(palette).map(k => [k, outlineColor])), x + ox, y + yOffset + oy, scale);
+  }
+
+  // Draw character normally on top
+  drawSpriteDef(ctx, sprite, palette, x, y + yOffset, scale);
+}
+ 
+// Note: z-sorting must be handled externally by calling drawCharacter in order of ascending y
+// This function only draws a single character with outline and shadow
+// Characters with higher y should be drawn later to appear on top
+// This matches acceptance criteria for simple z-sorting
